import{_ as n,c as a,a as i,o as e}from"./app-CEcM0piI.js";const l={};function d(p,s){return e(),a("div",null,s[0]||(s[0]=[i(`<p>定义宏用 define 去定义宏是在预编译的时候进行替换。 宏定义也可以用小写，但通常用大写字母，作为对变量的区分。</p><h2 id="_1、不带参宏" tabindex="-1"><a class="header-anchor" href="#_1、不带参宏"><span>1、不带参宏</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#define PI 3.14</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在预编译的时候如果代码中出现了 PI 就用 3.14 去替换宏的好处:只要修改宏定义，其他地方在预编译的时候就会重新替换注意:宏定义后边不要加分号。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#define PI 3.1415926</span></span>
<span class="line"><span>int main()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	double f;</span></span>
<span class="line"><span>	printf(&quot;%lf&quot;,PI);</span></span>
<span class="line"><span>	#undef PI//终止PI的作用</span></span>
<span class="line"><span>	retunr 0;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>宏定义的作用范围，从定义的地方到本文件末尾。如果想在中间终止宏的定义范围可用undef</p><h2 id="_2、带参宏" tabindex="-1"><a class="header-anchor" href="#_2、带参宏"><span>2、带参宏</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#define S(a,b) a*b</span></span>
<span class="line"><span>int main(int argc,char *argv[])</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	int num;</span></span>
<span class="line"><span>	num=S(2,4)//2*4</span></span>
<span class="line"><span>	num=S(3+5,7)//3+5*7 可以在定义带参宏时加括号</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	return 0;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>注意带参宏的形参 a 和b没有类型名，S(2,4) 将来在预处理的时候替换成 实参替代字符串的形参，其他字符保留</p><h2 id="_3、带参宏和带参函数的区别" tabindex="-1"><a class="header-anchor" href="#_3、带参宏和带参函数的区别"><span>3、带参宏和带参函数的区别</span></a></h2><p>带参宏被调用多少次就会展开多少次，执行代码的时候没有函数调用的过程，不需要压栈弹栈。所以带参宏，是浪费了空间，因为被展开多次，节省时间。 带参函数，代码只有一份，存在代码段，调用的时候去代码段取指令，调用的时候要，压栈弹栈。有个调用的过程。 所以说，带参函数是浪费了时间，节省了空间。</p><p>带参函数的形参是有类型的，带参宏的形参没有类型名</p><h1 id="选择性编译" tabindex="-1"><a class="header-anchor" href="#选择性编译"><span>选择性编译</span></a></h1><h2 id="_1、" tabindex="-1"><a class="header-anchor" href="#_1、"><span>1、</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#ifdef AAA</span></span>
<span class="line"><span>	代码段一</span></span>
<span class="line"><span>#else</span></span>
<span class="line"><span>	代码段二</span></span>
<span class="line"><span>#endif</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果在当前.c文件 ifdef 上边定义过 AAA ，就编译代码段一，否则编译代码段二</p><p>注意和 if else 语句的区别，if else 语句都会被编译，通过条件选择性执行代码而选择性编译，只有一块代码被编译。</p><h2 id="_2、" tabindex="-1"><a class="header-anchor" href="#_2、"><span>2、</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#ifndef AAA</span></span>
<span class="line"><span>	代码段一</span></span>
<span class="line"><span>#else</span></span>
<span class="line"><span>	代码段二</span></span>
<span class="line"><span>#endif</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>和第一种互补。如果在当前.c文件 ifdef 上边没有定义过 AAA ，就编译代码段一，否则编译代码段二。</p><p>经常用在防止头文件重复包含。 在fun.h文件中写入内容就可以防止头文件重复包含，两段代码一样</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#ifndef __FUN_H__</span></span>
<span class="line"><span>#define __FUN_H__</span></span>
<span class="line"><span>extern int fun(int x,int y);</span></span>
<span class="line"><span>#endif</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果头文件没有重复包含就执行该代码及#endif之前的代码定义宏__FUN_H__，如果重复头文件包含则在第二段的ifndef之前就定义过宏则不执行以后的内容。</p><h2 id="_3、" tabindex="-1"><a class="header-anchor" href="#_3、"><span>3、</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#if 表达式</span></span>
<span class="line"><span>	程序段一</span></span>
<span class="line"><span>#else</span></span>
<span class="line"><span>	程序段二</span></span>
<span class="line"><span>#endif</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果表达式为真，编译第一段代码，否则编译第二段代码 选择性编译都是在预编译阶段干的事情。</p><h1 id="宏函数-带参数的宏" tabindex="-1"><a class="header-anchor" href="#宏函数-带参数的宏"><span>宏函数（带参数的宏）</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#define trace(x,y) printf(#x&quot;=%&quot; #y&quot;\\n&quot;,x)  </span></span>
<span class="line"><span>int main() {  </span></span>
<span class="line"><span>    char(* name)[]=&quot;tom&quot;;  </span></span>
<span class="line"><span>    printf(&quot;%s\\n&quot;,name);  </span></span>
<span class="line"><span>    trace(name,s);  </span></span>
<span class="line"><span>    trace(name,a);  </span></span>
<span class="line"><span>    return 0;  </span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="字符串化" tabindex="-1"><a class="header-anchor" href="#字符串化"><span># 字符串化</span></a></h2><p># 的意思是把该变量名变为字符串 以trace(name,s)为例</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//printf( #x     &quot;=%&quot;   #y    &quot;\\n&quot; ,  x   )  </span></span>
<span class="line"><span>//printf(&quot;name&quot;  &quot;=%&quot;   &quot;s&quot;   &quot;\\n&quot; ,  name)</span></span>
<span class="line"><span>//printf(&quot;name=%s\\n&quot;,name)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>由于这几个字符串连着所以就将他们合并成一个字符串</p><h2 id="续行符" tabindex="-1"><a class="header-anchor" href="#续行符"><span>续行符\\</span></a></h2><p>由于宏定义必须在一行内完成 为了多行定义宏就需要用到续行符表示这一行并未结束后面还有</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#define SHOW_SIZEOF_AND_ALIGNOF(T)                                   \\  </span></span>
<span class="line"><span>  do {                                                               \\  </span></span>
<span class="line"><span>    cout &lt;&lt; &quot;sizeof(&quot; &lt;&lt; #T &lt;&lt; &quot;):\\t&quot; &lt;&lt; sizeof(T) &lt;&lt; &quot;,\\t&quot;          \\  </span></span>
<span class="line"><span>         &lt;&lt; &quot;alignof(&quot; &lt;&lt; #T &lt;&lt; &quot;):\\t&quot; &lt;&lt; alignof(T) &lt;&lt; endl;        \\  </span></span>
<span class="line"><span>  }while(0)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="标记拼接" tabindex="-1"><a class="header-anchor" href="#标记拼接"><span>标记拼接</span></a></h2><p>可以将两个变量拼接成字符串</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#define trace(x,format) printf(#x&quot;=%&quot;#format &quot;\\n&quot;,x)  </span></span>
<span class="line"><span>#define trace2(i)trace(salary ## i,d)  </span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>int main(void) {  </span></span>
<span class="line"><span>    int salary1 = 10000, salary2 = 15000, salary3 = 20000;  </span></span>
<span class="line"><span>    trace2(1);  </span></span>
<span class="line"><span>    trace2(2);  </span></span>
<span class="line"><span>    trace2(3);  </span></span>
<span class="line"><span>    return 0;  </span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="使用宏定义自己的调试语句" tabindex="-1"><a class="header-anchor" href="#使用宏定义自己的调试语句"><span>使用宏定义自己的调试语句</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#define PRINT(fmt,...) \\  </span></span>
<span class="line"><span>    printf(&quot;[file:%s][func:%s][line:%d]&quot;fmt, \\  </span></span>
<span class="line"><span>    __FILE__,__FUNCTION__ ,__LINE__,__VA_ARGS__)  </span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>int main() {  </span></span>
<span class="line"><span>    int sum=0;  </span></span>
<span class="line"><span>    for (int i = 0; i &lt; 5; i++) {  </span></span>
<span class="line"><span>        sum+=i;  </span></span>
<span class="line"><span>        PRINT(&quot;sum=%d\\n&quot;,sum);  </span></span>
<span class="line"><span>        PRINT(&quot;sum=%d,i=%d\\n&quot;,sum,i);  </span></span>
<span class="line"><span>    }  </span></span>
<span class="line"><span>    return 0;  </span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="宏的可变参数" tabindex="-1"><a class="header-anchor" href="#宏的可变参数"><span>宏的可变参数</span></a></h2><p>在宏命名中使用<span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mi mathvariant="normal">.</mi><mi mathvariant="normal">.</mi><mi mathvariant="normal">.</mi></mrow><annotation encoding="application/x-tex">...</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.1056em;"></span><span class="mord">...</span></span></span></span> 表明可变参数 宏定义中使用__VA_ARGS__表示可变参数（编译器的特性）</p><h2 id="可以通关宏定义调试宏的开关" tabindex="-1"><a class="header-anchor" href="#可以通关宏定义调试宏的开关"><span>可以通关宏定义调试宏的开关</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#define DEBUG 1  </span></span>
<span class="line"><span>#if DEBUG  </span></span>
<span class="line"><span>#define PRINT(fmt,...) \\  </span></span>
<span class="line"><span>    printf(&quot;[file:%s][func:%s][line:%d]&quot;fmt, \\  </span></span>
<span class="line"><span>    __FILE__,__FUNCTION__ ,__LINE__,__VA_ARGS__)  </span></span>
<span class="line"><span>#else  </span></span>
<span class="line"><span>#define PRINT(fmt,...)  </span></span>
<span class="line"><span>#endif</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在else语句中定义了空的宏函数，通过DEBUG是否为0选择使用哪个宏函数</p><h1 id="嵌套定义宏" tabindex="-1"><a class="header-anchor" href="#嵌套定义宏"><span>嵌套定义宏</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#define F(f) f (args)  </span></span>
<span class="line"><span>#define args a, b  </span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>void test(int n1, int n2) {  </span></span>
<span class="line"><span>    printf(&quot;%d+%d=%d\\n&quot;,n1, n2, n1 + n2);  </span></span>
<span class="line"><span>}  </span></span>
<span class="line"><span>int main(void) {  </span></span>
<span class="line"><span>    int a = 100,b = 200;  </span></span>
<span class="line"><span>    F(test); //100+200=300  </span></span>
<span class="line"><span>    //test(args)</span><span>    //test(a,b)}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,47)]))}const r=n(l,[["render",d]]),c=JSON.parse('{"path":"/cpp/c/8/","title":"8 宏定义","lang":"zh-CN","frontmatter":{"title":"8 宏定义","createTime":"2025/06/22 10:50:06","permalink":"/cpp/c/8/"},"readingTime":{"minutes":3.9,"words":1170},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/C/8 宏定义.md","headers":[]}');export{r as comp,c as data};
